THE RISK:
{
 "id": "statista-pipeline-mw-inflation",
 "title": "The CE-7 = 39.8% hop is built on Statista MW that don't reconcile with anyone else's Europe — pipeline capacity counted as PDU-buying capacity",
 "narrative": "Every geo ratio and the CE-7-of-Europe multiplier come from one Statista table whose summed 2024 country figures (~7.6GW) exceed CBRE's 4,726MW European colocation supply and even CBRE's 5.8GW total European DC capacity. Something in Statista's 'colocation and scale-colocation IT power' definition counts capacity that is contracted or under construction, not energized — Germany 'growing' 24.8% in a single forecast year while CBRE reports only 937MW of new supply for all of Europe is the tell. PDUs are bought at fit-out, per energized MW. If the padding is concentrated in the growth markets (Germany, Poland) rather than the mature FLAPD stock, the CE-7 share of Europe is overstated on a delivered-capacity basis — and the venture's Year-1 window is sized against halls that won't be racked for two years.",
 "category": "fact",
 "targetNodes": [
  "tamBase"
 ],
 "mechanism": [
  {
   "step": "trigger",
   "text": "Statista's summed 2024 per-country colo figures (~7.6GW) exceed CBRE's Q4-2024 European colocation supply (4,726MW) and approach-exceed CBRE's 5.8GW total European DC capacity — an unreconciled >1.6x scope gap in the sole source behind the CE-7 apportionment",
   "refs": [
    "digest:geo-region-denominator#c1",
    "digest:geo-region-denominator#c3",
    "digest:geo-region-denominator#c5"
   ]
  },
  {
   "step": "propagation",
   "text": "The inflation is growth-market-skewed: Statista shows Germany jumping 1,737→2,167 MW (+24.8%) and Poland +27.6% in 2026, while CBRE counts only 937MW of new supply delivered across all of Europe in 2025 — meaning the CE-7 numerator carries proportionally more announced/contracted capacity than the FLAPD-heavy denominator",
   "refs": [
    "digest:geo-region-denominator#c2",
    "digest:geo-region-denominator#c7",
    "ledger:geo.DE"
   ]
  },
  {
   "step": "model-impact",
   "text": "The 39.8% CE-7-of-Europe multiplier in tamBase's derivation is overstated on an energized-MW basis; rack-PDU spend follows fit-out of live halls, so the CE base for the venture's 12-month window is smaller than the ledger's €320M implies",
   "refs": [
    "ledger:tamBase"
   ]
  }
 ],
 "whyMissable": "The geo nodes look robust because they are internally cross-checked (BMWK, DDCA, Mordor, CBRE Suisse) — but every cross-check validates a different country against a different scope, and none reconciles the Statista Europe-wide sum against an independent Europe total. Internal consistency of ratios masks a scope error in the level.",
 "expectedObviousness": "medium",
 "falsifier": "A reconciliation showing Statista's country figures are live energized IT power — e.g., CBRE country pages independently confirming Germany at ~1,700MW+ live colocation in 2025.",
 "likelihood": {
  "value": 0.22,
  "rationale": "The 7.6GW-vs-4.7/5.8GW gap is documented and large, but part of it may be coverage (30 countries vs CBRE's top-15) rather than pipeline padding; the direction of CE-skew is inferred, not measured. [evidence revision: The raw magnitude gap (Statista ~7.6GW vs CBRE 4,726MW/5.8GW) is confirmed, but the load-bearing interpretation is materially weakened: CBRE's own note that its supply is limited to 'top 15 European markets' explains much of the excess as coverage rather than pipeline padding, and independent German sources (GDA ~1,955MW, firstcolo/GDA 1.3GW+, CBRE Frankfurt 1.02GW live) show Germany's Statista figure is broadly consistent with live/energized capacity — partially satisfying the stated falsifier. The scope-gap trigger is corroborated but the pipeline-padding-skews-CE-numerator mechanism is contested and not measured, so likelihood drops modestly.]",
  "basis": "evidence",
  "revisedFrom": 0.3
 },
 "perturbation": [
  {
   "nodeId": "tamBase",
   "op": "scale",
   "value": 0.85,
   "note": "CE-7 share of Europe ~39.8% → ~34% on a delivered/energized-capacity basis"
  }
 ],
 "indicators": [
  {
   "signal": "Delivered (not announced) MW per CE market versus Statista's year-over-year increments",
   "where": "CBRE quarterly 'Europe Data Centres Figures' (Frankfurt/secondary-market delivery tables)",
   "threshold": "Frankfurt+Berlin deliveries <200MW in 2026 against Statista's implied +430MW for Germany",
   "updates": "increases"
  },
  {
   "signal": "Energization delays cited by CE operators (grid connection queues in Frankfurt, Amsterdam moratorium after-effects)",
   "where": "Operator capex/earnings calls (Vantage, NTT GDC, Data4) and German TSO (TenneT/Amprion) connection-queue disclosures",
   "threshold": "Multiple operators pushing CE energization dates by ≥12 months",
   "updates": "increases"
  }
 ],
 "mitigations": [
  {
   "action": "Rebuild the CE-7 apportionment on a delivered-capacity series (CBRE quarterly figures) instead of the Statista snapshot, and diff the two",
   "type": "information",
   "voiNodeId": "tamBase",
   "note": "One analyst-week; directly tests whether the 39.8% hop survives a scope change"
  },
  {
   "action": "Time the sales-capacity ramp to tracked fit-out starts rather than announced MW — hire against delivered capacity milestones",
   "type": "operational",
   "voiNodeId": null,
   "note": "Converts the sizing risk into a pacing decision instead of a fixed-cost bet"
  }
 ],
 "evidenceStatus": "contested",
 "evidence": [
  {
   "title": "Europe Data Centres Figures Q4 2024",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025-02",
   "excerpt": "4,726MW European colocation supply... Note: Figures are representative of top 15 European markets covered by CBRE. CBRE expects almost 1GW of new data centre supply to be delivered (937MW) in 2025.",
   "url": "https://assoimmobiliare-be.afterpixel.com/app/uploads/2025/02/Europe-Data-Centres-Figures-Q4-2024.pdf",
   "attached": true
  },
  {
   "title": "Data Center Impact Report Deutschland 2024",
   "sourceType": "industry-report",
   "publisher": "German Datacenter Association",
   "date": "2024",
   "excerpt": "1,955 MW IT power in Germany approx... 831 MW IT power in Frankfurt colocation data centers. *Colocation and enterprise data centers > 50 kW",
   "url": "https://www.germandatacenters.com/fileadmin/images/DCIRD-24/Data-Center-Impact-Report-Deutschland-2024_EN.pdf",
   "attached": true
  },
  {
   "title": "Frankfurt Becomes a 1GW Data Centre Market",
   "sourceType": "industry-report",
   "publisher": "CBRE",
   "date": "2025-08-14",
   "excerpt": "the Frankfurt market closed at 1.02GW in the second quarter, including 26MW of new capacity",
   "url": "https://www.cbre.co.uk/press-releases/frankfurt-becomes-a-1gw-data-centre-market-narrowing-the-gap-with-london",
   "attached": true
  }
 ],
 "stances": [
  {
   "url": "https://www.statista.com/statistics/1659712/europe-colocation-data-center-power-by-country/",
   "stance": "supports",
   "quote": "| 2024 | 1,660 | 1,458 | 915 | 760 | 485 | 352 | 267 | 243 | 240 | 197 | 190 | 157 | 115 | 91 | 77 | 65 | 64 | 53 | 35 | 34 | 32 | 28 | 26 | 17 | 14 | 14 | 14 | 12 | 10 | 5 |"
  },
  {
   "url": "https://assoimmobiliare-be.afterpixel.com/app/uploads/2025/02/Europe-Data-Centres-Figures-Q4-2024.pdf",
   "stance": "supports",
   "quote": "4,726MW European colocation supply 470MW European colocation availability 341MW European colocation take-up"
  },
  {
   "url": "https://www.cbre.com/insights/reports/european-data-centres-overview",
   "stance": "supports",
   "quote": "5.8GW\n\nData centre capacity expected across Europe by the end of 2024"
  },
  {
   "url": "https://www.germandatacenters.com/fileadmin/images/DCIRD-24/Data-Center-Impact-Report-Deutschland-2024_EN.pdf",
   "stance": "contradicts",
   "quote": "1,955 MW IT power in Germany approx."
  },
  {
   "url": "https://firstcolo.net/en/datacenter-outlook-2025-26-digital-sovereignty/",
   "stance": "contradicts",
   "quote": "With over 1.3 GW of installed IT capacity, Germany is Europe’s largest data center market."
  },
  {
   "url": "https://www.cbre.co.uk/press-releases/frankfurt-becomes-a-1gw-data-centre-market-narrowing-the-gap-with-london",
   "stance": "contradicts",
   "quote": "the Frankfurt market closed at 1.02GW in the second quarter, including 26MW of new capacity"
  }
 ]
}

